callGraph.callee:
dept.groups
    .map(function (g) {
      var title = cleanEstudio(g.title || '');
      if (isSkippedGroupTitle(title) || isCommentNoiseEstudio(title)) return null;
      g.rows = (g.rows || []).filter(function (r) {
        return r && !isCommentNoiseEstudio(r.estudio) && !isSkippedGroupTitle(r.estudio);
      });
      return g;
    })
    .filter

sensCrudas
    .map(function (s) {
      var itTrim = String(s.interp || '').trim();
      var bucket = classifyAtbInterp(itTrim);
      var label = bucket === 's' ? 'S' : bucket === 'i' ? 'I' : 'R';
      var med = String(s.med || '').trim();
      var mic = String(s.mic || '').trim();
      var title = escTxt(
        med + (mic ? ' ' + mic : '') + (itTrim ? ' — ' + itTrim : '')
      );
      return (
        '<span class="atb-chip atb-chip--' +
        bucket +
        '" title="' +
        title +
        '" tabindex="0">' +
        escTxt(label) +
        '</span>'
      );
    })
    .join

meds.map(function (row) {
      return {
        medicamento: String(row && row.medicamento != null ? row.medicamento : ''),
        presentacion: String(row && row.presentacion != null ? row.presentacion : ''),
        dosis: String(row && row.dosis != null ? row.dosis : ''),
      };
    }).filter

listSelectableTables(parsed, { reportDate })
    .filter((item) => idSet.has(item.id))
    .map((item) => {
      const dept = parsed.departments[item.deptIndex];
      const group = dept?.groups?.[item.groupIndex];
      if (!group) return null;
      return groupToSesionTable(group, {
        tabTitle: item.tabTitle,
        isAdmission: item.isAdmission,
        reportDate,
      });
    })
    .filter

items
    .map(({ spec, index }) => {
      const fk = spec.fieldKey;
      const values = axisMeta.points.map((p) => {
        const v = getSetTrendValueForSeries(p.set, sectionKey, fk);
        return v != null && Number.isFinite(v) ? v : null;
      });
      if (!values.some((v) => v != null)) return null;
      let visible = true;
      if (savedVisible && savedVisible.length) {
        visible = savedVisible.includes(fk);
      }
      return {
        fieldKey: fk,
        label: seriesLabel(sectionKey, spec),
        color: readSeriesColor(sectionKey, fk) || defaultSeriesColor(index),
        visible,
        unit: rt.unitForField(fk) || '',
        values,
      };
    })
    .filter

row.cells
      .map(function (cell, ci) {
        return { cell: cell, col: model.columns[ci] };
      })
      .filter(function (x) {
        return x.col && !x.col.hidden;
      })
      .map

